"""Shared shutdown event for graceful server shutdown.

Used by the runtime lifespan (set on exit) and the identity token poller
(wait on it) so that Ctrl+C / SIGINT causes the poller to exit promptly.
"""

import asyncio
from typing import Optional

_shutdown_event: Optional[asyncio.Event] = None


def get_shutdown_event() -> asyncio.Event:
    """Return the process-wide shutdown event, creating it lazily if needed.

    The event is set when the server lifespan exits (e.g. on Ctrl+C).
    Pollers wait on this event together with their sleep interval so they
    wake and exit as soon as shutdown is requested.
    """
    global _shutdown_event
    if _shutdown_event is None:
        _shutdown_event = asyncio.Event()
    return _shutdown_event
